#nullable enable // autogenerated  

using MVZ2.Vanilla.Properties;

using PVZEngine.Buffs;
using PVZEngine.Definitions;
using PVZEngine.Modifiers;

namespace MVZ2.GameContent.Buffs.Entities
{
    [AutoBuffDefinition(VanillaBuffNames.Entity.NuclearDiffusion)]
    public class NuclearDiffusionBuff : BuffDefinition
    {
        public NuclearDiffusionBuff(string nsp, string name) : base(nsp, name)
        {
            // PROP_HEALTH_REDUCTION 存的是负数，Add 即为减少最大生命值  
            AddModifier(new MaxHealthModifier(NumberOperator.Add, PROP_HEALTH_REDUCTION));
        }
        public static readonly VanillaBuffPropertyMeta<float> PROP_HEALTH_REDUCTION = new VanillaBuffPropertyMeta<float>("health_reduction", 0f);
    }
}
